return items.map(item => {
  let orderDate = item.json.Order_Date;

  if (orderDate) {
    let day, month, year;

    if (orderDate.includes("-")) {
      [day, month, year] = orderDate.split("-");
    } else if (orderDate.includes("/")) {
      [day, month, year] = orderDate.split("/");
    }

    if (day && month && year) {
      day = day.padStart(2, "0");
      month = month.padStart(2, "0");

      item.json.order_date = `${year}-${month}-${day}`;
    }
  }

  return item;
});
